   686	- (void)installVApp:(WBVAppModel *)vapp {
   687	    vapp.progress = 0.0;
   688	    CFAbsoluteTime start = CFAbsoluteTimeGetCurrent();
   689	    [self saveStatus:WBVappStatusInstalling forVApp:vapp];
   690	    
   691	    [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeVappInstalling defaultHandler:nil];
   692	    
   693	    [WBStorageManager.sharedManager unzipIPAForVapp:vapp progressHandler:^(long entryNumber, long total) {
   694	        CGFloat progress = ((CGFloat)entryNumber)/(total+1);
   695	        if (progress> 0.01+vapp.progress) {
   696	            vapp.progress = progress;
   697	            [vapp setInMemoryStatus:WBVappStatusInstalling];
   698	            NSLog(@"unzipping ipa: %f", progress);
   699	        }
   700	    } completionHandler:^(NSString * path, BOOL succeeded, NSError * error) {
   701	        if (succeeded) {
   702	            NSLog(@"Install: success unziped at %@", path);
   703	            NSString *user = vapp.userInfo.user;
   704	            NSString *bundleId = vapp.bundleId;
   705	            [WBEventManager logVappInstallEvent:vapp];
   706	            OAAErr result;
   707	            NSString *version;
   708	            if (!user) {
   709	                version = vapp.versionInfo.version;
   710	                result = oaa_install_vapp(path, &bundleId, &version, &user);
   711	            } else {
   712	                if (vapp.versionInfo.prevVersion == vapp.versionInfo.version) {
   713	                    version = vapp.versionInfo.version;
   714	                    result = oaa_reinstall_vapp(path, &bundleId, &version);
   715	                } else {
   716	                    version = vapp.versionInfo.prevVersion;
   717	                    result = oaa_upgrade_vapp(path, bundleId, &version);
   718	                }
   719	            }
   720	            NSLog(@"Install: res:%d", result);
   721	            if (result == oaaErrSuccess) {
   722	                vapp.userInfo.user = user;
   723	                vapp.bundleId = bundleId;
   724	                vapp.versionInfo.version = version;
   725	                vapp.progress = 1.0;
   726	                [self saveStatus:WBVappStatusInstalled forVApp:vapp];
   727	                [WBEventManager logVappInstallResultEvent:vapp result:@"0" timeCost:(NSInteger)(CFAbsoluteTimeGetCurrent()-start)];
   728	            } else {
   729	                vapp.progress = 0.0;
   730	                PostNotificationOnMainThread(WBVAppInstallErrorNotification, vapp);
   731	                [self saveStatus:WBVappStatusInstallError forVApp:vapp];
   732	                NSString *errorMsg = [self errorMessageForOAAErr:result];
   733	                [[WBVAppManager sharedManager] saveError:WBVappStatusInstallError
   734	                                             errorDomain:WBErrorDomainVAppOAA
   735	                                              errorCode:result
   736	                                           errorMessage:errorMsg
   737	                                               forVApp:vapp];
   738	                [WBEventManager logVappInstallResultEvent:vapp result:errorMsg timeCost:(NSInteger)(CFAbsoluteTimeGetCurrent()-start)];
   739	            }
   740	            
   741	            // Start downloading vapp resources, which may include bytecodes and other optional resources.
   742	            if (![WBStorageManager.sharedManager hasRes:vapp ofSha1Hash:vapp.versionInfo.resHash]) {
   743	                if ([[vapp.versionInfo.resURL lowercaseString] hasPrefix:@"http"]) {
   744	                    [WBVAppResDownloadManager.sharedManager addToDownloadQueue:vapp];
   745	                } else {
   746	                    [self saveStatus:WBVappStatusResourceDownloadGiveUp forVApp:vapp];
   747	                }
   748	            } else {
   749	                [self saveStatus:WBVappStatusResourceDownloaded forVApp:vapp];
   750	                [[WBStorageManager sharedManager] unzipRes:vapp];
   751	            }
   752	            
   753	        } else {
   754	            PostNotificationOnMainThread(WBVAppInstallErrorNotification, vapp);
   755	            [self saveStatus:WBVappStatusInstallError forVApp:vapp];
   756	            [self saveError:WBVappStatusInstallError
   757	                errorDomain:error.domain
   758	                  errorCode:error.code
   759	               errorMessage:error.localizedDescription
   760	                    forVApp:vapp];
   761	            [WBEventManager logVappInstallResultEvent:vapp result:error.localizedDescription timeCost:(NSInteger)(CFAbsoluteTimeGetCurrent()-start)];
   762	        }
   763	    }];
   764	}
