- (UIView *)generateRichMessageBannerViewWithBannerModel:(WBBannerModel *)bannerModel {
    UIView *productView = [[UIView alloc] init];
    UIView *mainView = [self _generateMainView:bannerModel];
    CGFloat mainViewHeight = WBRpt(200);
    UIView *headerView = [self _generateHeaderView:bannerModel];
    [productView addSubview:mainView];
    [productView addSubview:headerView];
    [headerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(productView).offset(WBRpt(8));
        make.left.right.equalTo(productView);
        make.height.mas_equalTo(WBRpt(32));
    }];
    [mainView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(headerView.mas_bottom).offset(WBRpt(4));
        make.left.right.equalTo(productView);
        make.bottom.equalTo(productView).offset(-WBRpt(8));
        make.height.mas_equalTo(mainViewHeight);
    }];
    return productView;
}这里的mainview和headerview有什么区别

