   275	        _allApps[vapp.bundle_id] = current;
   276	    } else if (vapp.scheme != nil && current.scheme == nil) {
   277	        // merge the scheme field, for local WBVappScheme.plist datas
   278	        current.scheme = vapp.scheme;
   279	    } else if (vapp.reserve_count > current.reserveCount) {
   280	        // update with the maximum
   281	        current.reserveCount = vapp.reserve_count;
   282	    }
   283	    current.visible = vapp.visible;
   284	    
   285	    return current;
